import { existsSync, mkdirSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { type AssistantMessage, type AssistantMessageEvent, EventStream, getModel } from "@mariozechner/pi-ai";
import { Type } from "@sinclair/typebox";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { AuthStorage } from "../src/core/auth-storage.js";
import type { ExtensionUIContext, ToolDefinition } from "../src/core/extensions/types.js";
import { ModelRegistry } from "../src/core/model-registry.js";
import { createAgentSession } from "../src/core/sdk.js";
import { theme } from "../src/modes/interactive/theme/theme.js";

class MockAssistantStream extends EventStream<AssistantMessageEvent, AssistantMessage> {
	constructor() {
		super(
			(event) => event.type === "done" || event.type === "error",
			(event) => {
				if (event.type === "done") return event.message;
				if (event.type === "error") return event.error;
				throw new Error("Unexpected event type");
			},
		);
	}
}

function createAssistantMessage(
	content: AssistantMessage["content"],
	stopReason: AssistantMessage["stopReason"],
): AssistantMessage {
	return {
		role: "assistant",
		content,
		api: "anthropic-messages",
		provider: "anthropic",
		model: "mock",
		usage: {
			input: 0,
			output: 0,
			cacheRead: 0,
			cacheWrite: 0,
			totalTokens: 0,
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
		},
		stopReason,
		timestamp: Date.now(),
	};
}

describe("interactive tool concurrency (real session wiring)", () => {
	let tempDir: string;
	let agentDir: string;
	let session: Awaited<ReturnType<typeof createAgentSession>>["session"] | undefined;

	beforeEach(() => {
		tempDir = join(tmpdir(), `pi-interactive-tool-concurrency-${Date.now()}`);
		agentDir = join(tempDir, "agent");
		mkdirSync(tempDir, { recursive: true });
		mkdirSync(agentDir, { recursive: true });
	});

	afterEach(() => {
		session?.dispose();
		if (tempDir && existsSync(tempDir)) {
			rmSync(tempDir, { recursive: true, force: true });
		}
	});

	it("should complete when two interactive tools are called in one turn", async () => {
		const model = getModel("anthropic", "claude-sonnet-4-5")!;
		const authStorage = AuthStorage.create(join(agentDir, "auth.json"));
		authStorage.setRuntimeApiKey("anthropic", "test-key");
		const modelRegistry = new ModelRegistry(authStorage, join(agentDir, "models.json"));

		const askTool = (name: "ask_a" | "ask_b") => {
			const schema = Type.Object({});
			const tool: ToolDefinition<typeof schema> = {
				name,
				label: name,
				description: name,
				parameters: schema,
				async execute(_toolCallId, _params, _signal, _onUpdate, ctx) {
					const answer = await ctx.ui.input(name, "answer");
					return {
						content: [{ type: "text" as const, text: `${name}:${answer ?? "none"}` }],
						details: {},
					};
				},
			};
			return tool as unknown as ToolDefinition;
		};

		const created = await createAgentSession({
			cwd: tempDir,
			agentDir,
			authStorage,
			modelRegistry,
			model,
			customTools: [askTool("ask_a"), askTool("ask_b")],
		});
		session = created.session;

		let llmCallCount = 0;
		session.agent.streamFn = async (_model, context) => {
			const stream = new MockAssistantStream();
			queueMicrotask(() => {
				const toolResultCount = context.messages.filter((message) => message.role === "toolResult").length;
				if (toolResultCount >= 2) {
					const done = createAssistantMessage([{ type: "text", text: "done" }], "stop");
					stream.push({ type: "start", partial: { ...done, content: [] } });
					stream.push({ type: "done", reason: "stop", message: done });
					return;
				}

				if (llmCallCount === 0) {
					const withTools = createAssistantMessage(
						[
							{ type: "toolCall", id: "toolu_a", name: "ask_a", arguments: {} },
							{ type: "toolCall", id: "toolu_b", name: "ask_b", arguments: {} },
						],
						"toolUse",
					);
					stream.push({ type: "start", partial: { ...withTools, content: [] } });
					stream.push({ type: "done", reason: "toolUse", message: withTools });
					llmCallCount++;
				}
			});
			return stream;
		};

		let activeInputResolve: ((value: string | undefined) => void) | undefined;
		const uiContext: ExtensionUIContext = {
			select: async () => undefined,
			confirm: async () => false,
			input: async () =>
				await new Promise<string | undefined>((resolve) => {
					// Emulate real interactive slot behavior: last dialog owns UI.
					activeInputResolve = resolve;
				}),
			notify: () => {},
			onTerminalInput: () => () => {},
			setStatus: () => {},
			setWorkingMessage: () => {},
			setWidget: () => {},
			setFooter: () => {},
			setHeader: () => {},
			setTitle: () => {},
			custom: async () => undefined as never,
			pasteToEditor: () => {},
			setEditorText: () => {},
			getEditorText: () => "",
			editor: async () => undefined,
			setEditorComponent: () => {},
			get theme() {
				return theme;
			},
			getAllThemes: () => [],
			getTheme: () => undefined,
			setTheme: () => ({ success: false, error: "not used" }),
			getToolsExpanded: () => false,
			setToolsExpanded: () => {},
		};

		await session.bindExtensions({ uiContext });

		const promptPromise = session.prompt("run both interactive tools");
		await new Promise((resolve) => setTimeout(resolve, 20));
		activeInputResolve?.("ok");

		const outcome = await Promise.race([
			promptPromise.then(() => "done" as const),
			new Promise<"timeout">((resolve) => setTimeout(() => resolve("timeout"), 250)),
		]);

		expect(outcome).toBe("done");
	});
});

